class Solution:
    def longestCommonPrefix(self, arr1, arr2):
        best = 0
        for x in arr1:
            sx = str(x)
            for y in arr2:
                sy = str(y)
                l = min(len(sx), len(sy))
                cur = 0
                for i in range(l):
                    if sx[i] == sy[i]:
                        cur += 1
                    else:
                        break
                best = max(best, cur)
        return best

