var longestCommonPrefix = function(arr1, arr2) {
    const prefixes = new Set();
    for (const x of arr1) {
        const s = String(x);
        for (let i = 1; i <= s.length; i++) {
            prefixes.add(s.slice(0, i));
        }
    }
    let best = 0;
    for (const y of arr2) {
        const s = String(y);
        for (let i = 1; i <= s.length; i++) {
            if (prefixes.has(s.slice(0, i))) {
                best = Math.max(best, i);
            }
        }
    }
    return best;
};
